const ambientes = [
  { nombre: 'Dev',     url: 'https://www.clinicabupasantiago.cl/', ambiente: 'dev' },
  { nombre: 'Staging', url: 'https://www.clinicabupasantiago.cl/', ambiente: 'staging' },
  { nombre: 'UAT',     url: 'https://www.clinicabupasantiago.cl/', ambiente: 'uat' },
];

const resultados = [];

for (const amb of ambientes) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'GET',
      url: amb.url,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      timeout: 10000,
    });
    resultados.push({
      ...amb,
      statusCode: resp.statusCode,
      status: resp.statusCode === 200 ? 'UP' : 'DOWN',
      ok: resp.statusCode === 200,
    });
  } catch (err) {
    resultados.push({
      ...amb,
      statusCode: 0,
      status: 'DOWN',
      ok: false,
      error: err.message,
    });
  }
}

const caidos    = resultados.filter(r => !r.ok);
const activos   = resultados.filter(r => r.ok);
const fecha     = new Date().toLocaleString('es-CL', { timeZone: 'America/Santiago' });
const date      = new Date().toISOString().split('T')[0];
const hayCaidos = caidos.length > 0;

return [{ json: { resultados, caidos, activos, hayCaidos, fecha, date, total: resultados.length } }];

const item      = $input.first().json;
const caidos    = item.caidos    || [];
const resultados = item.resultados || [];
const fecha     = item.fecha;
const date      = item.date;

// ── Jira payload (ADF) ───────────────────────────────────────────────────────
const jiraPayload = {
  fields: {
    project:   { key: 'KAN' },
    summary:   `🚨 Ambiente(s) QA caído(s) — ${caidos.map(c => c.nombre).join(', ')} | ${date}`,
    issuetype: { name: 'Bug' },
    priority:  { name: 'High' },
    description: {
      type: 'doc', version: 1,
      content: [
        { type: 'paragraph', content: [{ type: 'text', text: `Health check fallido el ${fecha}. Ambientes con problemas:` }] },
        {
          type: 'bulletList',
          content: caidos.map(c => ({
            type: 'listItem',
            content: [{ type: 'paragraph', content: [{ type: 'text', text: `${c.nombre}: ${c.url} — HTTP ${c.statusCode || 'CONNECTION ERROR'}` }] }]
          }))
        },
        { type: 'paragraph', content: [{ type: 'text', text: 'Creado automáticamente por WF-1.5 Health Check QA. No iniciar testing hasta resolver.' }] }
      ]
    }
  }
};

// ── Email HTML rojo ───────────────────────────────────────────────────────────
const rows = resultados.map(r => {
  const bg     = r.ok ? '#dcfce7' : '#fee2e2';
  const color  = r.ok ? '#166534' : '#b91c1c';
  const icon   = r.ok ? '🟢' : '🔴';
  const estado = r.ok ? `✅ UP (${r.statusCode})` : `❌ DOWN (${r.statusCode || 'ERROR'})`;
  return `<tr style="background:${bg}">
    <td style="border:1px solid #e5e7eb;padding:10px 14px;font-weight:700">${icon} ${r.nombre}</td>
    <td style="border:1px solid #e5e7eb;padding:10px 14px;font-size:12px"><a href="${r.url}" style="color:#1d4ed8">${r.url}</a></td>
    <td style="border:1px solid #e5e7eb;padding:10px 14px;text-align:center;font-weight:700;color:${color}">${estado}</td>
  </tr>`;
}).join('');

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#fef2f2;font-family:Arial,sans-serif">
<div style="max-width:700px;margin:0 auto;padding:24px 16px">
  <div style="background:linear-gradient(135deg,#b91c1c,#dc2626);color:#fff;padding:20px 24px;border-radius:10px 10px 0 0">
    <h2 style="margin:0;font-size:18px">🚨 ALERTA — Ambiente(s) QA Caído(s)</h2>
    <p style="margin:6px 0 0;font-size:13px;opacity:.85">${fecha} | ${caidos.length} de ${resultados.length} ambiente(s) con problemas</p>
  </div>
  <div style="background:#fff;border:1px solid #fecaca;border-top:none;padding:24px;border-radius:0 0 10px 10px">
    <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:12px;margin-bottom:20px">
      <div style="background:#fee2e2;border-radius:8px;padding:14px;text-align:center">
        <div style="font-size:28px;font-weight:700;color:#b91c1c">${caidos.length}</div>
        <div style="font-size:11px;color:#991b1b;margin-top:4px">🔴 CAÍDOS</div>
      </div>
      <div style="background:#dcfce7;border-radius:8px;padding:14px;text-align:center">
        <div style="font-size:28px;font-weight:700;color:#166534">${resultados.length - caidos.length}</div>
        <div style="font-size:11px;color:#14532d;margin-top:4px">🟢 ACTIVOS</div>
      </div>
    </div>
    <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse">
      <tr style="background:#b91c1c;color:#fff">
        <th style="padding:9px 14px;border:1px solid #fecaca;text-align:left;font-size:12px">Ambiente</th>
        <th style="padding:9px 14px;border:1px solid #fecaca;text-align:left;font-size:12px">URL</th>
        <th style="padding:9px 14px;border:1px solid #fecaca;text-align:center;font-size:12px">Estado</th>
      </tr>
      ${rows}
    </table>
    <p style="margin-top:16px;font-size:12px;color:#6b7280">⚠️ Bug creado automáticamente en Jira KAN. No iniciar testing hasta resolver.</p>
  </div>
</div></body></html>`;

// ── WhatsApp mensaje alerta ───────────────────────────────────────────────────
const waLineas  = resultados.map(r => `${r.ok ? '🟢' : '🔴'} ${r.nombre}: ${r.ok ? 'UP' : 'DOWN'}`).join('\n');
const waMensaje = `🚨 *ALERTA QA — Ambientes Caídos*\n${fecha}\n\n${waLineas}\n\n⚠️ ${caidos.length} ambiente(s) fuera de servicio.\nBug creado en Jira KAN.\n❌ No iniciar testing hasta resolver.`;

return [{
  json: {
    ...item,
    jiraPayload,
    emailPayload: {
      to:      'jaimeqv.2609@gmail.com,javi.gajardo26@gmail.com',
      subject: `🚨 ALERTA QA — ${caidos.length} Ambiente(s) Caído(s) | ${date}`,
      html
    },
    mensajeWhatsApp: encodeURIComponent(waMensaje)
  }
}];

const item       = $input.first().json;
const resultados = item.resultados || [];
const fecha      = item.fecha;
const date       = item.date;

// ── Email HTML verde ──────────────────────────────────────────────────────────
const rows = resultados.map(r =>
  `<tr style="background:#dcfce7">
    <td style="border:1px solid #bbf7d0;padding:10px 14px;font-weight:700">🟢 ${r.nombre}</td>
    <td style="border:1px solid #bbf7d0;padding:10px 14px;font-size:12px"><a href="${r.url}" style="color:#1d4ed8">${r.url}</a></td>
    <td style="border:1px solid #bbf7d0;padding:10px 14px;text-align:center;font-weight:700;color:#166534">✅ UP (${r.statusCode})</td>
  </tr>`
).join('');

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f0fdf4;font-family:Arial,sans-serif">
<div style="max-width:700px;margin:0 auto;padding:24px 16px">
  <div style="background:linear-gradient(135deg,#15803d,#16a34a);color:#fff;padding:20px 24px;border-radius:10px 10px 0 0">
    <h2 style="margin:0;font-size:18px">✅ Todos los Ambientes QA Operativos</h2>
    <p style="margin:6px 0 0;font-size:13px;opacity:.85">${fecha} | ${resultados.length}/${resultados.length} ambientes activos</p>
  </div>
  <div style="background:#fff;border:1px solid #bbf7d0;border-top:none;padding:24px;border-radius:0 0 10px 10px">
    <div style="background:#dcfce7;border-radius:8px;padding:14px;text-align:center;margin-bottom:20px">
      <div style="font-size:36px;font-weight:700;color:#15803d">${resultados.length}/${resultados.length}</div>
      <div style="font-size:12px;color:#166534;margin-top:4px">🟢 TODOS LOS AMBIENTES ACTIVOS</div>
    </div>
    <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse">
      <tr style="background:#15803d;color:#fff">
        <th style="padding:9px 14px;border:1px solid #bbf7d0;text-align:left;font-size:12px">Ambiente</th>
        <th style="padding:9px 14px;border:1px solid #bbf7d0;text-align:left;font-size:12px">URL</th>
        <th style="padding:9px 14px;border:1px solid #bbf7d0;text-align:center;font-size:12px">Estado</th>
      </tr>
      ${rows}
    </table>
    <p style="margin-top:16px;font-size:12px;color:#6b7280">✅ Ambiente verificado — puede iniciar la jornada de testing.</p>
  </div>
</div></body></html>`;

// ── WhatsApp mensaje OK ───────────────────────────────────────────────────────
const waLineas  = resultados.map(r => `🟢 ${r.nombre}: UP (${r.statusCode})`).join('\n');
const waMensaje = `✅ *Ambientes QA — Todo OK*\n${fecha}\n\n${waLineas}\n\n🧪 Puede iniciar la jornada de testing sin problemas.`;

return [{
  json: {
    ...item,
    emailPayload: {
      to:      'jaimeqv.2609@gmail.com,javi.gajardo26@gmail.com',
      subject: `✅ Ambientes QA OK — ${resultados.length}/${resultados.length} activos | ${date}`,
      html
    },
    mensajeWhatsApp: encodeURIComponent(waMensaje)
  }
}];
